  def heroicon(name, klass: "w-5 h-5")
    path = HEROICONS[name.to_sym]
    return "" if path.nil?

    content_tag :svg,
                path.html_safe,
                xmlns: "http://www.w3.org/2000/svg",
                fill: "none",
                viewBox: "0 0 24 24",
                "stroke-width": "1.5",
                stroke: "currentColor",
                "aria-hidden": "true",
                class: klass
  end
